import React from 'react';
import { useParams, Link } from 'react-router-dom';
import Card from '../components/common/Card';
import ResultSummary from '../components/results/ResultSummary';
import CodeSnapshotPanel from '../components/job/CodeSnapshotPanel'; // Re-using for context
import RawOutput from '../components/results/RawOutput';
import AIChatWorkspace from './AIChatWorkspace'; // The contextual AI panel

const mockResult = {
  sessionId: 'session-abc-123',
  jobName: 'Q3 Financial Risk Analysis',
  status: 'Completed',
  solver: 'Quantum Risk Solver v1.2',
  summary: {
    'Execution Time': '45.2s',
    'Risk Metric': '0.87',
    'Confidence Interval': '95%',
  },
  rawOutput: JSON.stringify(
    {
      results: {
        risk_score: 0.873,
        parameters: { confidence: 0.95, time_horizon: '1y' },
        execution_trace: ['...log data...'],
      },
    },
    null,
    2
  ),
  codeSnapshot: `import numpy as np

def run_solver(data):
    # Simplified risk calculation
    risk = np.mean(data['amount']) / 1000
    return {"risk_score": risk}
  `,
};

function Results() {
  const { sessionId } = useParams(); // Assuming routing by session ID

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      <div className="lg:col-span-2">
        <div className="p-4 bg-gray-100 rounded-t-lg border-b mb-4">
            <h2 className="text-xl font-bold">Analysis Results</h2>
            <p className="text-sm text-gray-600">Session ID: {sessionId || mockResult.sessionId}</p>
        </div>

        <Card>
            <h3 className="text-lg font-semibold">{mockResult.jobName}</h3>
            <p className="text-sm text-gray-500 mb-4">Solver: {mockResult.solver}</p>
            <ResultSummary summary={mockResult.summary} />
            <RawOutput output={mockResult.rawOutput} />
            <div className="mt-6">
              <Link to="/history" className="text-blue-500 hover:underline">&larr; Back to Job History</Link>
            </div>
        </Card>

        <div className="mt-8">
            <CodeSnapshotPanel code={mockResult.codeSnapshot} />
        </div>
      </div>

      <div className="lg:col-span-1">
          <div className="sticky top-4">
            <h3 className="text-lg font-semibold mb-2">Contextual AI Assistant</h3>
            <AIChatWorkspace />
          </div>
      </div>
    </div>
  );
}

export default Results;
